INSERT INTO FSI_DEMO_DB.WEALTH_MANAGEMENT.ADVISOR_NOTES (NOTE_ID, CLIENT_ID, ADVISOR_ID, NOTE_DATE, MEETING_TYPE, DURATION_MINUTES, ATTENDEES, CONTENT, SUMMARY, ACTION_ITEMS, FOLLOW_UP_DATE, TOPICS_DISCUSSED, CLIENT_SENTIMENT, CREATED_AT) VALUES
('AN0000000', 'WC0000000', 'ADV0000', '2026-02-17 14:32:01.097', 'ANNUAL_REVIEW', '15', 'Client, Advisor', 'Conducted comprehensive annual portfolio review with client. Reviewed performance versus benchmarks - portfolio outperformed by 1.2% YTD. Discussed asset allocation and confirmed it remains aligned with stated risk tolerance. Client expressed satisfaction with current strategy but inquired about increasing international exposure. Recommended gradual shift of 5% from domestic to international equities over next quarter. Also discussed estate planning updates needed following birth of grandchild.', 'Annual review complete; increasing intl exposure 5%; estate planning update needed', '1) Implement 5% shift to international. 2) Contact estate attorney for document updates. 3) Schedule follow-up in 90 days.', '2026-03-03', 'Portfolio Review, Asset Allocation, Estate Planning', 'VERY_POSITIVE', '2026-02-17 14:32:01.097'),
('AN0000001', 'WC0000001', 'ADV0001', '2026-02-17 12:52:01.097', 'QUARTERLY_CHECK_IN', '22', 'Client, Spouse, Advisor', 'Quarterly check-in call. Markets have been volatile but client portfolio has held up well due to diversification. Client mentioned potential job change that could impact cash flow needs. Discussed contingency plans including reducing contributions temporarily if needed. Reviewed progress on retirement goal - currently at 72% of target with 8 years to go. On track assuming 7% average returns.', 'Quarterly check-in; potential job change discussed; retirement goal on track at 72%', '1) Monitor employment situation. 2) Prepare contingency cash flow scenarios. 3) Next quarterly call in October.', '2026-03-06', 'Goal Progress, Cash Flow, Market Update', 'POSITIVE', '2026-02-17 14:32:01.097'),
('AN0000002', 'WC0000002', 'ADV0002', '2026-02-17 11:12:01.097', 'PHONE_CALL', '29', 'Client, Advisor, Portfolio Manager', 'Client called with concerns about recent market downturn. Took time to review historical market corrections and long-term performance data. Emphasized importance of staying invested and avoiding emotional decisions. Client seemed reassured after discussion. Reminded them of their 15+ year time horizon and conservative allocation already in place. No changes to portfolio recommended at this time.', 'Client concerns addressed re: market volatility; no portfolio changes', '1) Send market perspective article. 2) Check in again in 2 weeks. 3) No portfolio changes.', '2026-03-09', 'Market Volatility, Risk Tolerance, Long-term Strategy', 'NEUTRAL', '2026-02-17 14:32:01.097'),
('AN0000003', 'WC0000003', 'ADV0003', '2026-02-17 09:32:01.097', 'VIDEO_CONFERENCE', '36', 'Client, Advisor, Tax Specialist', 'Video call to discuss upcoming liquidity needs. Client planning major home renovation estimated at $50003. Reviewed options including portfolio withdrawal vs. home equity line. Recommended combination approach to minimize tax impact. Will prepare detailed cash flow analysis showing optimal withdrawal strategy across accounts.', 'Home renovation funding strategy discussed; preparing cash flow analysis', '1) Prepare detailed withdrawal strategy analysis. 2) Model tax implications. 3) Meet again in 2 weeks with recommendations.', '2026-03-12', 'Liquidity Needs, Tax Planning, Withdrawal Strategy', 'CONCERNED', '2026-02-17 14:32:01.097'),
('AN0000004', 'WC0000004', 'ADV0004', '2026-02-17 07:52:01.097', 'IN_PERSON', '43', 'Client, Advisor', 'Met with client and spouse to review estate planning documents. Current beneficiary designations are outdated following daughters marriage. Action needed to update IRA and 401k beneficiaries. Also discussed potential for establishing 529 plans for future grandchildren. Introduced estate planning attorney for trust discussion.', 'Estate planning review; beneficiary updates needed; 529 plans discussed', '1) Client to gather beneficiary forms. 2) Schedule call with estate attorney. 3) Research 529 options.', '2026-03-15', 'Estate Planning, Beneficiaries, Education Funding', 'POSITIVE', '2026-02-17 14:32:01.097'),
('AN0000005', 'WC0000005', 'ADV0005', '2026-02-17 06:12:01.097', 'EMAIL_FOLLOW_UP', '50', 'Client, Spouse, Advisor', 'Client requested meeting to discuss sustainable investing options. Reviewed ESG-focused funds available in our platform. Discussed trade-offs between ESG constraints and potential returns. Client decided to allocate 30% of portfolio to ESG strategies. Will implement changes over next 30 days using tax-loss harvesting to offset any gains.', 'ESG investing discussion; allocating 30% to sustainable strategies', '1) Implement ESG allocation changes. 2) Identify TLH opportunities. 3) Send ESG fund performance reports.', '2026-03-18', 'ESG Investing, Values Alignment, Portfolio Transition', 'VERY_POSITIVE', '2026-02-17 14:32:01.097'),
('AN0000006', 'WC0000006', 'ADV0006', '2026-02-17 04:32:01.097', 'ANNUAL_REVIEW', '57', 'Client, Advisor, Portfolio Manager', 'Annual tax planning session with client and their CPA. Reviewed YTD realized gains and losses. Identified opportunities for tax-loss harvesting totaling approximately $5006. Discussed Roth conversion strategy given clients lower income this year. Agreed to convert $50,000 from Traditional IRA to Roth before year end.', 'Tax planning session; TLH opportunities identified; Roth conversion planned', '1) Execute tax-loss harvesting trades. 2) Process Roth conversion. 3) Coordinate with CPA on documentation.', '2026-03-21', 'Tax Optimization, Roth Conversion, Loss Harvesting', 'POSITIVE', '2026-02-17 14:32:01.097'),
('AN0000007', 'WC0000007', 'ADV0007', '2026-02-17 02:52:01.097', 'QUARTERLY_CHECK_IN', '64', 'Client, Advisor, Tax Specialist', 'Proactive outreach following Fed interest rate announcement. Explained potential impact on bond portfolio and overall allocation. Client appreciated the communication. Reviewed current fixed income holdings - duration is appropriate given outlook. No immediate changes needed but will continue monitoring.', 'Rate decision follow-up; no changes needed to fixed income', '1) Continue monitoring rates. 2) Send monthly fixed income update. 3) Review duration in 60 days.', '2026-03-24', 'Retirement Planning, Income Strategy, Social Security', 'NEUTRAL', '2026-02-17 14:32:01.097'),
('AN0000008', 'WC0000008', 'ADV0008', '2026-02-17 01:12:01.097', 'PHONE_CALL', '71', 'Client, Advisor', 'Client approaching retirement in 18 months. Detailed discussion of income strategy and Social Security timing. Ran multiple scenarios showing impact of claiming at 62 vs 67 vs 70. Recommended delaying to age 67 given health history and portfolio size. Began transitioning portfolio toward more income-generating positions.', 'Pre-retirement planning; Social Security timing analyzed; income strategy begun', '1) Begin portfolio transition to income focus. 2) Finalize Social Security filing date. 3) Create retirement income projection.', '2026-03-27', 'Portfolio Review, Asset Allocation, Estate Planning', 'CONCERNED', '2026-02-17 14:32:01.097'),
('AN0000009', 'WC0000009', 'ADV0009', '2026-02-16 23:32:01.097', 'VIDEO_CONFERENCE', '78', 'Client, Spouse, Advisor', 'Follow-up on previous discussion about charitable giving strategy. Client wishes to donate $10009 to alma mater. Reviewed options including direct gift, donor-advised fund, and qualified charitable distribution from IRA. Recommended QCD given clients age (72) and RMD requirements. Will coordinate with charity for proper documentation.', 'Charitable giving strategy; recommending QCD for $10009 donation', '1) Coordinate QCD with charity. 2) Obtain tax documentation. 3) Confirm receipt of funds.', '2026-03-30', 'Goal Progress, Cash Flow, Market Update', 'POSITIVE', '2026-02-17 14:32:01.097'),
