-- FSI_DEMO_DB.WEALTH_MANAGEMENT.ADVISOR_NOTES

CREATE OR REPLACE TABLE FSI_DEMO_DB.WEALTH_MANAGEMENT.ADVISOR_NOTES (

    NOTE_ID VARCHAR(20) NOT NULL,
    CLIENT_ID VARCHAR(20),
    ADVISOR_ID VARCHAR(20),
    NOTE_DATE TIMESTAMP_NTZ(9),
    MEETING_TYPE VARCHAR(50),
    DURATION_MINUTES NUMBER(5,0),
    ATTENDEES VARCHAR(500),
    CONTENT VARCHAR(16777216),
    SUMMARY VARCHAR(1000),
    ACTION_ITEMS VARCHAR(16777216),
    FOLLOW_UP_DATE DATE,
    TOPICS_DISCUSSED VARCHAR(500),
    CLIENT_SENTIMENT VARCHAR(30),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (NOTE_ID)

);



